let domain = 'tesla.com';
try {
  const webhookData = $('Webhook Scan').first().json;
  if (webhookData) {
    const input = webhookData.target || webhookData.domain 
      || (webhookData.body && (webhookData.body.target || webhookData.body.domain));
    if (input) {
      domain = input.trim().toLowerCase();
      domain = domain.replace(/[^a-z0-9.-]/g, '');
    }
  }
} catch(e) {}
return [{ json: { target_domain: domain } }];

const domain = $('Definir Objetivos').first().json.target_domain;
const tipos = ['A', 'AAAA', 'MX', 'NS', 'TXT', 'SOA'];
const resultados = {};

function dnsQuery(domain, tipo) {
  return new Promise(function(resolve) {
    const https = require('https');
    const url = 'https://dns.google/resolve?name=' + encodeURIComponent(domain) + '&type=' + encodeURIComponent(tipo);
    https.get(url, function(res) {
      let body = '';
      res.on('data', function(chunk) { body += chunk; });
      res.on('end', function() {
        try {
          const data = JSON.parse(body);
          resolve((data.Answer || []).map(function(r) { return r.data; }));
        } catch(e) {
          resolve([]);
        }
      });
    }).on('error', function() {
      resolve([]);
    });
  });
}

for (const tipo of tipos) {
  resultados[tipo] = await dnsQuery(domain, tipo);
}

const ipPrincipal = resultados.A && resultados.A.length > 0 ? resultados.A[0] : 'No encontrada';

return [{
  json: {
    target_domain: domain,
    target_ip: ipPrincipal,
    dns: resultados
  }
}];

const ip = $('DNS Completo').first().json.target_ip;

const data = await new Promise(function(resolve) {
  const https = require('https');
  https.get('https://internetdb.shodan.io/' + encodeURIComponent(ip), { timeout: 10000 }, function(res) {
    let body = '';
    res.on('data', function(chunk) { body += chunk; });
    res.on('end', function() {
      try { resolve(JSON.parse(body)); }
      catch(e) { resolve({}); }
    });
  }).on('error', function() { resolve({}); })
    .on('timeout', function() { resolve({}); });
});

return [{ json: data }];

const domain = $('Definir Objetivos').first().json.target_domain;

function httpsGet(url, maxRedirects) {
  return new Promise(function(resolve) {
    const https = require('https');
    const http = require('http');
    const isHttps = url.indexOf('https://') === 0;
    const mod = isHttps ? https : http;

    mod.get(url, { timeout: 15000 }, function(res) {
      if ((res.statusCode === 301 || res.statusCode === 302) && res.headers.location && maxRedirects > 0) {
        resolve(httpsGet(res.headers.location, maxRedirects - 1));
        return;
      }
      let body = '';
      res.on('data', function(chunk) { body += chunk; });
      res.on('end', function() {
        try { resolve(JSON.parse(body)); }
        catch(e) { resolve({}); }
      });
    }).on('error', function() { resolve({}); })
      .on('timeout', function() { resolve({}); });
  });
}

const data = await httpsGet('https://rdap.org/domain/' + encodeURIComponent(domain), 5);

return [{ json: data }];

var domain = $('Definir Objetivos').first().json.target_domain;
var https = require('https');
var http = require('http');

function httpsGet(url, attempt, maxAttempts) {
  attempt = attempt || 1;
  maxAttempts = maxAttempts || 2;
  return new Promise(function(resolve) {
    var mod = url.indexOf('https://') === 0 ? https : http;
    var req = mod.get(url, { timeout: 20000, headers: { 'User-Agent': 'n8n-osint-scanner/2.0', 'Accept': 'application/json' } }, function(res) {
      var body = '';
      res.on('data', function(chunk) { body += chunk; });
      res.on('end', function() { resolve({ status: res.statusCode, body: body }); });
    });
    req.on('error', function() {
      if (attempt < maxAttempts) { setTimeout(function() { resolve(httpsGet(url, attempt + 1, maxAttempts)); }, 2000); }
      else { resolve({ status: 0, body: '' }); }
    });
    req.on('timeout', function() {
      req.destroy();
      if (attempt < maxAttempts) { setTimeout(function() { resolve(httpsGet(url, attempt + 1, maxAttempts)); }, 2000); }
      else { resolve({ status: 0, body: '' }); }
    });
    req.end();
  });
}

// === Source 1: crt.sh ===
function fetchCrtSh() {
  return httpsGet('https://crt.sh/?q=' + encodeURIComponent(domain) + '&output=json', 1, 3).then(function(res) {
    var subs = [];
    try {
      var data = JSON.parse(res.body);
      var unique = {};
      data.forEach(function(entry) {
        var names = [];
        if (entry.common_name) names.push(entry.common_name.toLowerCase().trim());
        if (entry.name_value) {
          entry.name_value.split(String.fromCharCode(10)).forEach(function(v) {
            var cleaned = v.toLowerCase().trim();
            if (cleaned) names.push(cleaned);
          });
        }
        names.forEach(function(name) {
          if (name.indexOf('*') === -1) unique[name] = true;
        });
      });
      subs = Object.keys(unique);
    } catch(e) {}
    return { source: 'crt.sh', subdomains: subs };
  });
}

// === Source 2: HackerTarget ===
function fetchHackerTarget() {
  return httpsGet('https://api.hackertarget.com/hostsearch/?q=' + encodeURIComponent(domain), 1, 2).then(function(res) {
    var subs = [];
    try {
      if (res.status === 200 && res.body && res.body.indexOf('error') === -1 && res.body.indexOf('API count exceeded') === -1) {
        var lines = res.body.trim().split(String.fromCharCode(10));
        lines.forEach(function(line) {
          var parts = line.split(',');
          if (parts[0]) {
            var sub = parts[0].toLowerCase().trim();
            if (sub && sub.indexOf(domain) >= 0) subs.push(sub);
          }
        });
      }
    } catch(e) {}
    return { source: 'hackertarget', subdomains: subs };
  });
}

// === Source 3: AlienVault OTX ===
function fetchAlienVault() {
  return httpsGet('https://otx.alienvault.com/api/v1/indicators/domain/' + encodeURIComponent(domain) + '/passive_dns', 1, 2).then(function(res) {
    var subs = [];
    try {
      if (res.status === 200) {
        var data = JSON.parse(res.body);
        var records = data.passive_dns || [];
        records.forEach(function(rec) {
          if (rec.hostname) {
            var h = rec.hostname.toLowerCase().trim();
            if (h.indexOf(domain) >= 0 && h.indexOf('*') === -1) subs.push(h);
          }
        });
      }
    } catch(e) {}
    return { source: 'alienvault_otx', subdomains: subs };
  });
}

// === Source 4: URLScan.io ===
function fetchUrlscan() {
  return httpsGet('https://urlscan.io/api/v1/search/?q=domain:' + encodeURIComponent(domain) + '&size=100', 1, 2).then(function(res) {
    var subs = [];
    try {
      if (res.status === 200) {
        var data = JSON.parse(res.body);
        var results = data.results || [];
        var unique = {};
        results.forEach(function(r) {
          if (r.page && r.page.domain) {
            var d = r.page.domain.toLowerCase().trim();
            if (d.indexOf(domain) >= 0 && !unique[d]) { unique[d] = true; subs.push(d); }
          }
        });
      }
    } catch(e) {}
    return { source: 'urlscan', subdomains: subs };
  });
}

// === Run all sources in parallel ===
var results = await Promise.all([
  fetchCrtSh(),
  fetchHackerTarget(),
  fetchAlienVault(),
  fetchUrlscan()
]);

// === Merge and deduplicate ===
var allSubs = {};
var sourceSummary = {};

results.forEach(function(r) {
  sourceSummary[r.source] = r.subdomains.length;
  r.subdomains.forEach(function(sub) {
    if (!allSubs[sub]) {
      allSubs[sub] = [];
    }
    if (allSubs[sub].indexOf(r.source) === -1) {
      allSubs[sub].push(r.source);
    }
  });
});

var subdomainList = Object.keys(allSubs).sort();
var subdomainsWithSources = subdomainList.map(function(sub) {
  return { name: sub, sources: allSubs[sub] };
});

return [{ json: {
  subdomains: subdomainList,
  subdomainsWithSources: subdomainsWithSources,
  count: subdomainList.length,
  sourceSummary: sourceSummary,
  sourcesUsed: ['crt.sh', 'hackertarget', 'alienvault_otx', 'urlscan']
}}];

var domain = $('Definir Objetivos').first().json.target_domain;
var https = require('https');

function githubSearch(path) {
  return new Promise(function(resolve) {
    var options = {
      hostname: 'api.github.com',
      path: path,
      method: 'GET',
      timeout: 15000,
      headers: {
        'User-Agent': 'n8n-osint-scanner/1.0',
        'Accept': 'application/vnd.github.v3+json'
      }
    };
    var req = https.request(options, function(res) {
      var body = '';
      res.on('data', function(chunk) { body += chunk; });
      res.on('end', function() {
        try { resolve(JSON.parse(body)); }
        catch(e) { resolve({ items: [] }); }
      });
    });
    req.on('error', function() { resolve({ items: [] }); });
    req.on('timeout', function() { req.destroy(); resolve({ items: [] }); });
    req.end();
  });
}

var repoData = await githubSearch('/search/repositories?q=' + encodeURIComponent(domain) + '&per_page=10&sort=stars&order=desc');
var repos = (repoData.items || []).map(function(r) {
  return {
    name: r.full_name || '',
    description: (r.description || '').substring(0, 120),
    stars: r.stargazers_count || 0,
    language: r.language || 'N/A',
    url: r.html_url || '',
    updated: r.updated_at || ''
  };
});

var domainBase = domain.split('.')[0];
var orgData = await githubSearch('/search/users?q=' + encodeURIComponent(domainBase) + '+type:org&per_page=10');
var orgs = (orgData.items || []).map(function(o) {
  return {
    login: o.login || '',
    url: o.html_url || '',
    avatar: o.avatar_url || '',
    type: o.type || 'Organization'
  };
});

return [{ json: { github_repos: repos, github_orgs: orgs, repos_count: repos.length, orgs_count: orgs.length } }];

var ip = $('DNS Completo').first().json.target_ip;
var http = require('http');

var geoData = await new Promise(function(resolve) {
  var options = {
    hostname: 'ip-api.com',
    path: '/json/' + encodeURIComponent(ip),
    method: 'GET',
    timeout: 10000
  };
  var req = http.request(options, function(res) {
    var body = '';
    res.on('data', function(chunk) { body += chunk; });
    res.on('end', function() {
      try { resolve(JSON.parse(body)); }
      catch(e) { resolve({}); }
    });
  });
  req.on('error', function() { resolve({}); });
  req.on('timeout', function() { req.destroy(); resolve({}); });
  req.end();
});

return [{ json: {
  geo_ip: ip,
  geo_country: geoData.country || 'N/A',
  geo_countryCode: geoData.countryCode || '',
  geo_region: geoData.regionName || 'N/A',
  geo_city: geoData.city || 'N/A',
  geo_lat: geoData.lat || 0,
  geo_lon: geoData.lon || 0,
  geo_isp: geoData.isp || 'N/A',
  geo_org: geoData.org || 'N/A',
  geo_as: geoData.as || 'N/A',
  geo_timezone: geoData.timezone || 'N/A'
} }];

var dnsData = $('DNS Completo').first().json;
var shodan = $('Shodan InternetDB').first().json;
var rdap = $('RDAP WHOIS').first().json;
var subData = $('Subdominios Multi-Fuente').first().json;
var ghData = $('GitHub OSINT').first().json;
var geoData = $('IP Geolocation').first().json;
var mxData = $('MXToolbox Check').first().json;

var domain = dnsData.target_domain;
var ip = dnsData.target_ip;
var dns = dnsData.dns;

// --- PORT MAP ---
var portMap = {20:'FTP-Data',21:'FTP',22:'SSH',23:'Telnet',25:'SMTP',53:'DNS',80:'HTTP',110:'POP3',143:'IMAP',443:'HTTPS',445:'SMB',993:'IMAPS',995:'POP3S',2053:'Unknown',2082:'cPanel',2083:'cPanel-SSL',2086:'WHM',2087:'WHM-SSL',2095:'Webmail',3306:'MySQL',3389:'RDP',5432:'PostgreSQL',8080:'HTTP-Proxy',8443:'HTTPS-Alt',8880:'HTTP-Alt',8888:'HTTP-Alt'};

// --- SHODAN ---
var shodanInfo = {
  ip: shodan.ip || ip,
  puertos: (shodan.ports || []).map(function(p) { return { port: p, service: portMap[p] || 'Unknown' }; }),
  hostnames: shodan.hostnames || [],
  vulns: shodan.vulns || [],
  cpes: shodan.cpes || [],
  tags: shodan.tags || []
};

// --- RELATED DOMAINS from Shodan hostnames ---
var relatedDomains = [];
(shodan.hostnames || []).forEach(function(h) {
  var cleaned = h.toLowerCase().trim();
  if (cleaned && cleaned !== domain && relatedDomains.indexOf(cleaned) === -1) {
    relatedDomains.push(cleaned);
  }
});

// --- WHOIS ---
var whoisInfo = {
  nombre_dominio: '', registrador: '', fecha_creacion: '', fecha_expiracion: '',
  estado: [], nameservers: [], entidades: []
};
if (rdap && !rdap.error && rdap.ldhName) {
  whoisInfo.nombre_dominio = rdap.ldhName || domain;
  whoisInfo.estado = rdap.status || [];
  if (rdap.events) {
    rdap.events.forEach(function(e) {
      if (e.eventAction === 'registration') whoisInfo.fecha_creacion = e.eventDate || '';
      if (e.eventAction === 'expiration') whoisInfo.fecha_expiracion = e.eventDate || '';
    });
  }
  if (rdap.nameservers) {
    whoisInfo.nameservers = rdap.nameservers.map(function(ns) { return ns.ldhName || ''; });
  }
  if (rdap.entities) {
    rdap.entities.forEach(function(ent) {
      var roles = (ent.roles || []).join(', ');
      var nombre = '';
      if (ent.vcardArray && ent.vcardArray[1]) {
        ent.vcardArray[1].forEach(function(v) {
          if (v[0] === 'fn') nombre = v[3] || '';
        });
      }
      if (ent.handle) whoisInfo.registrador = whoisInfo.registrador || ent.handle;
      if (nombre || roles) whoisInfo.entidades.push({ nombre: nombre, roles: roles, handle: ent.handle || '' });
    });
  }
}

// --- EMAIL SECURITY: SPF, DKIM, DMARC ---
var txtRecords = dns.TXT || [];
var spf = { found: false, record: '', details: '' };
var dkim = { found: false, details: '' };
var dmarc = { found: false, record: '', policy: '', details: '' };

txtRecords.forEach(function(rec) {
  var recLower = rec.toLowerCase();
  if (recLower.indexOf('v=spf1') >= 0) {
    spf.found = true;
    spf.record = rec;
    if (recLower.indexOf('-all') >= 0) spf.details = 'Strict (-all): solo IPs autorizadas pueden enviar email';
    else if (recLower.indexOf('~all') >= 0) spf.details = 'Soft fail (~all): IPs no autorizadas marcadas pero no rechazadas';
    else if (recLower.indexOf('+all') >= 0) spf.details = 'Permisivo (+all): PELIGROSO - cualquiera puede enviar email';
    else if (recLower.indexOf('?all') >= 0) spf.details = 'Neutral (?all): sin politica definida';
    else spf.details = 'SPF configurado';
  }
  if (recLower.indexOf('v=dkim') >= 0 || recLower.indexOf('dkim') >= 0) {
    dkim.found = true;
    dkim.details = rec;
  }
  if (recLower.indexOf('v=dmarc') >= 0) {
    dmarc.found = true;
    dmarc.record = rec;
    if (recLower.indexOf('p=reject') >= 0) { dmarc.policy = 'reject'; dmarc.details = 'Politica estricta: emails no autenticados son rechazados'; }
    else if (recLower.indexOf('p=quarantine') >= 0) { dmarc.policy = 'quarantine'; dmarc.details = 'Cuarentena: emails no autenticados van a spam'; }
    else if (recLower.indexOf('p=none') >= 0) { dmarc.policy = 'none'; dmarc.details = 'Solo monitoreo: no se toman acciones (inseguro)'; }
    else { dmarc.policy = 'unknown'; dmarc.details = 'Politica no reconocida'; }
  }
});

var emailSecurity = { spf: spf, dkim: dkim, dmarc: dmarc };

// --- EMAIL PATTERNS ---
var emailPatterns = [
  'info@' + domain, 'admin@' + domain, 'support@' + domain,
  'contact@' + domain, 'sales@' + domain, 'hr@' + domain,
  'security@' + domain, 'abuse@' + domain, 'webmaster@' + domain,
  'postmaster@' + domain, 'noreply@' + domain, 'help@' + domain,
  'billing@' + domain, 'legal@' + domain, 'marketing@' + domain,
  'press@' + domain, 'jobs@' + domain, 'careers@' + domain
];

// --- SUBDOMAINS ---
var subdomains = subData.subdomains || [];
var subdomainCount = subData.count || 0;
var subdomainsWithSources = subData.subdomainsWithSources || [];
var sourceSummary = subData.sourceSummary || {};
var sourcesUsed = subData.sourcesUsed || [];

// --- GITHUB ---
var githubRepos = ghData.github_repos || [];
var githubOrgs = ghData.github_orgs || [];

// --- GEOLOCATION ---
var geo = {
  ip: geoData.geo_ip || ip,
  country: geoData.geo_country || 'N/A',
  countryCode: geoData.geo_countryCode || '',
  region: geoData.geo_region || 'N/A',
  city: geoData.geo_city || 'N/A',
  lat: geoData.geo_lat || 0,
  lon: geoData.geo_lon || 0,
  isp: geoData.geo_isp || 'N/A',
  org: geoData.geo_org || 'N/A',
  asn: geoData.geo_as || 'N/A',
  timezone: geoData.geo_timezone || 'N/A'
};

// --- RISK SCORE (out of 100) ---
var riskScore = 0;
var riskFactors = [];

// Open ports risk
var riskyPorts = [21,22,23,25,445,3306,3389,5432];
var openPorts = shodan.ports || [];
if (openPorts.length > 10) { riskScore += 15; riskFactors.push('Mas de 10 puertos abiertos'); }
else if (openPorts.length > 5) { riskScore += 10; riskFactors.push(openPorts.length + ' puertos abiertos'); }
else if (openPorts.length > 0) { riskScore += 5; }
openPorts.forEach(function(p) {
  if (riskyPorts.indexOf(p) >= 0) { riskScore += 5; riskFactors.push('Puerto de alto riesgo abierto: ' + p + ' (' + (portMap[p]||'Unknown') + ')'); }
});

// Vulns risk
if (shodanInfo.vulns.length > 5) { riskScore += 30; riskFactors.push(shodanInfo.vulns.length + ' vulnerabilidades conocidas (critico)'); }
else if (shodanInfo.vulns.length > 0) { riskScore += 15 + shodanInfo.vulns.length * 3; riskFactors.push(shodanInfo.vulns.length + ' vulnerabilidades conocidas'); }

// Email security risk
if (!dmarc.found) { riskScore += 10; riskFactors.push('DMARC no configurado - vulnerable a spoofing'); }
else if (dmarc.policy === 'none') { riskScore += 5; riskFactors.push('DMARC en modo solo monitoreo'); }
if (!spf.found) { riskScore += 8; riskFactors.push('SPF no configurado'); }
else if (spf.record.toLowerCase().indexOf('+all') >= 0) { riskScore += 10; riskFactors.push('SPF permisivo (+all)'); }

// Cap at 100
if (riskScore > 100) riskScore = 100;

var riskLevel = 'BAJO';
if (riskScore >= 75) riskLevel = 'CRITICO';
else if (riskScore >= 50) riskLevel = 'ALTO';
else if (riskScore >= 25) riskLevel = 'MEDIO';

// --- EXECUTIVE SUMMARY ---
var keyFindings = [];
if (shodanInfo.vulns.length > 0) keyFindings.push('Se detectaron ' + shodanInfo.vulns.length + ' vulnerabilidades conocidas en la infraestructura.');
if (openPorts.length > 0) keyFindings.push('Se encontraron ' + openPorts.length + ' puertos abiertos expuestos a Internet.');
if (!dmarc.found || !spf.found) keyFindings.push('La configuracion de seguridad de email es deficiente.');
if (subdomainCount > 20) keyFindings.push('Se identificaron ' + subdomainCount + ' subdominios, lo que representa una superficie de ataque amplia.');
if (githubRepos.length > 0) keyFindings.push('Se encontraron ' + githubRepos.length + ' repositorios publicos relacionados en GitHub.');
if (keyFindings.length === 0) keyFindings.push('No se detectaron hallazgos criticos de seguridad en el analisis pasivo.');

var recommendations = [];
if (!dmarc.found) recommendations.push('Implementar politica DMARC con p=reject.');
if (!spf.found) recommendations.push('Configurar registro SPF restrictivo.');
if (shodanInfo.vulns.length > 0) recommendations.push('Parchear las vulnerabilidades detectadas de manera urgente.');
var riskyOpen = openPorts.filter(function(p) { return riskyPorts.indexOf(p) >= 0; });
if (riskyOpen.length > 0) recommendations.push('Revisar y restringir acceso a puertos de alto riesgo: ' + riskyOpen.join(', ') + '.');
if (subdomainCount > 20) recommendations.push('Auditar subdominios para identificar servicios obsoletos o expuestos.');
if (recommendations.length === 0) recommendations.push('Mantener la postura de seguridad actual y realizar escaneos periodicos.');

// --- DORKS ---
var dorks = [
  { icono: '&#128196;', nombre: 'Documentos expuestos', query: 'site:' + domain + ' filetype:pdf OR filetype:doc OR filetype:xls OR filetype:txt OR filetype:csv' },
  { icono: '&#128274;', nombre: 'Paneles de acceso', query: 'site:' + domain + ' inurl:login OR inurl:admin OR inurl:signin OR inurl:portal' },
  { icono: '&#128194;', nombre: 'Directorios abiertos', query: 'site:' + domain + ' intitle:"index of"' },
  { icono: '&#128269;', nombre: 'Informacion sensible', query: 'site:' + domain + ' intext:password OR intext:confidential OR intext:internal' },
  { icono: '&#127760;', nombre: 'Subdominios indexados', query: 'site:*.' + domain },
  { icono: '&#128736;', nombre: 'Tecnologias web', query: 'site:' + domain + ' inurl:wp-content OR inurl:wp-admin OR inurl:joomla OR inurl:drupal OR inurl:api' },
  { icono: '&#9888;', nombre: 'Errores y mensajes debug', query: 'site:' + domain + ' intext:"error" OR intext:"exception" OR intext:"stack trace"' },
  { icono: '&#128101;', nombre: 'Presencia digital', query: '"' + domain + '" site:linkedin.com OR site:github.com OR site:twitter.com' },
  { icono: '&#128273;', nombre: 'Archivos de configuracion', query: 'site:' + domain + ' filetype:env OR filetype:yml OR filetype:xml OR filetype:json OR filetype:ini' },
  { icono: '&#128187;', nombre: 'Codigo fuente expuesto', query: 'site:' + domain + ' filetype:php OR filetype:asp OR filetype:jsp OR filetype:sql' }
];

// Derive company name from domain
var companyName = domain.split('.')[0];
companyName = companyName.charAt(0).toUpperCase() + companyName.slice(1);

return [{
  json: {
    resumen: {
      dominio: domain,
      ip: ip,
      companyName: companyName,
      nivel_riesgo: riskLevel,
      riesgo_puntuacion: riskScore,
      riskFactors: riskFactors,
      dns: dns,
      shodan: shodanInfo,
      whois: whoisInfo,
      emailSecurity: emailSecurity,
      emailPatterns: emailPatterns,
      subdomains: subdomains,
      subdomainCount: subdomainCount,
      subdomainsWithSources: subdomainsWithSources,
      sourceSummary: sourceSummary,
      sourcesUsed: sourcesUsed,
      githubRepos: githubRepos,
      githubOrgs: githubOrgs,
      geo: geo,
      relatedDomains: relatedDomains,
      dorks: dorks,
      blacklist: mxData.blacklist,
      mxRecords: mxData.mx,
      mxLinks: mxData.mxLinks,
      keyFindings: keyFindings,
      recommendations: recommendations,
      timestamp: new Date().toISOString()
    }
  }
}];

var r = $('Generar Informe OSINT').first().json.resumen;
var fecha = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
function esc(s) { return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
