// Reverse IP for DNSBL queries
var parts = ip.split('.');
var reversed = parts[3] + '.' + parts[2] + '.' + parts[1] + '.' + parts[0];

// DNS Blacklists to check
var blacklists = [
  { name: 'Spamhaus ZEN', host: 'zen.spamhaus.org' },
  { name: 'SpamCop', host: 'bl.spamcop.net' },
  { name: 'Barracuda', host: 'b.barracudacentral.org' },
  { name: 'SORBS', host: 'dnsbl.sorbs.net' },
  { name: 'UCEPROTECT L1', host: 'dnsbl-1.uceprotect.net' },
  { name: 'Composite BL', host: 'cbl.abuseat.org' },
  { name: 'SpamRATS', host: 'noptr.spamrats.com' },
  { name: 'PSBL', host: 'psbl.surriel.com' }
];

function dnsCheck(query) {
  return new Promise(function(resolve) {
    var https = require('https');
    var url = 'https://dns.google/resolve?name=' + encodeURIComponent(query) + '&type=A';
    https.get(url, { timeout: 5000 }, function(res) {
      var body = '';
      res.on('data', function(c) { body += c; });
      res.on('end', function() {
        try {
          var data = JSON.parse(body);
          resolve(data.Answer && data.Answer.length > 0);
        } catch(e) { resolve(false); }
      });
    }).on('error', function() { resolve(false); })
      .on('timeout', function() { resolve(false); });
  });
}

var results = [];
for (var i = 0; i < blacklists.length; i++) {
  var bl = blacklists[i];
  var query = reversed + '.' + bl.host;
  var listed = await dnsCheck(query);
  results.push({ name: bl.name, host: bl.host, listed: listed });
}

var listedCount = results.filter(function(r) { return r.listed; }).length;

