var blacklists = [
  { name: 'Spamhaus ZEN', host: 'zen.spamhaus.org' },
  { name: 'SpamCop', host: 'bl.spamcop.net' },
  { name: 'Barracuda', host: 'b.barracudacentral.org' },
  { name: 'SORBS', host: 'dnsbl.sorbs.net' },
  { name: 'UCEPROTECT L1', host: 'dnsbl-1.uceprotect.net' },
  { name: 'Composite BL', host: 'cbl.abuseat.org' },
  { name: 'SpamRATS', host: 'noptr.spamrats.com' },
  { name: 'PSBL', host: 'psbl.surriel.com' }
];

function dnsCheck(query) {
  return new Promise(function(resolve) {
    var https = require('https');
    var url = 'https://dns.google/resolve?name=' + encodeURIComponent(query) + '&type=A';
    https.get(url, { timeout: 5000 }, function(res) {
      var body = '';
      res.on('data', function(c) { body += c; });
      res.on('end', function() {
        try {
          var data = JSON.parse(body);
          resolve(data.Answer && data.Answer.length > 0);
        } catch(e) { resolve(false); }
      });
    }).on('error', function() { resolve(false); })
      .on('timeout', function() { resolve(false); });
  });
}

var results = [];
for (var i = 0; i < blacklists.length; i++) {
  var bl = blacklists[i];
  var query = reversed + '.' + bl.host;
  var listed = await dnsCheck(query);
  results.push({ name: bl.name, host: bl.host, listed: listed });
}

var listedCount = results.filter(function(r) { return r.listed; }).length;

// Parse MX records for mail info
var mxRecords = (dns.MX || []).map(function(mx) {
  var parts = mx.split(' ');
  return { priority: parseInt(parts[0]) || 0, server: (parts[1] || mx).replace(/\.$/, '') };
}).sort(function(a, b) { return a.priority - b.priority; });

// Detect mail provider from MX
var mailProvider = 'Unknown';
var mxStr = mxRecords.map(function(m) { return m.server; }).join(' ').toLowerCase();
if (mxStr.indexOf('google') !== -1 || mxStr.indexOf('gmail') !== -1) mailProvider = 'Google Workspace';
else if (mxStr.indexOf('outlook') !== -1 || mxStr.indexOf('microsoft') !== -1) mailProvider = 'Microsoft 365';
else if (mxStr.indexOf('protonmail') !== -1) mailProvider = 'ProtonMail';
else if (mxStr.indexOf('zoho') !== -1) mailProvider = 'Zoho Mail';
else if (mxStr.indexOf('mimecast') !== -1) mailProvider = 'Mimecast';
else if (mxStr.indexOf('barracuda') !== -1) mailProvider = 'Barracuda';
else if (mxStr.indexOf('pphosted') !== -1) mailProvider = 'Proofpoint';
else if (mxRecords.length > 0) mailProvider = mxRecords[0].server;

// MXToolbox links
var mxLinks = [
  { name: 'MX Lookup', url: 'https://mxtoolbox.com/SuperTool.aspx?action=mx%3a' + domain, desc: 'Verifica registros MX y configuracion de correo' },
  { name: 'Blacklist Check', url: 'https://mxtoolbox.com/SuperTool.aspx?action=blacklist%3a' + domain, desc: 'Comprueba si el dominio esta en listas negras' },
  { name: 'SPF Check', url: 'https://mxtoolbox.com/SuperTool.aspx?action=spf%3a' + domain, desc: 'Valida la configuracion SPF' },
  { name: 'DMARC Check', url: 'https://mxtoolbox.com/SuperTool.aspx?action=dmarc%3a' + domain, desc: 'Verifica politica DMARC' },
  { name: 'DKIM Check', url: 'https://mxtoolbox.com/SuperTool.aspx?action=dkim%3a' + domain, desc: 'Comprueba registros DKIM' },
  { name: 'DNS Check', url: 'https://mxtoolbox.com/SuperTool.aspx?action=dns%3a' + domain, desc: 'Analisis completo de DNS' },
  { name: 'SMTP Test', url: 'https://mxtoolbox.com/SuperTool.aspx?action=smtp%3a' + domain, desc: 'Prueba conectividad SMTP' },
  { name: 'HTTP Headers', url: 'https://mxtoolbox.com/SuperTool.aspx?action=header%3a' + domain, desc: 'Analiza cabeceras HTTP de seguridad' }
];

return [{
  json: {
    blacklist: { results: results, listedCount: listedCount, totalChecked: blacklists.length },
    mx: { records: mxRecords, provider: mailProvider },
    mxLinks: mxLinks
  }
}];
